+/*
+  Reserve enough vertical space for the pricing comparison skeleton so a late
+  dynamic mount above the FAQ section is less likely to push the final TOC
+  anchor back below the fold after hash navigation.
+*/
+.sm-scope [data-viz="pricing-comparison"] [role="status"] {
+  min-height: 56rem;
+}
+
+@media (min-width: 768px) {
+  .sm-scope [data-viz="pricing-comparison"] [role="status"] {
+    min-height: 44rem;
+  }
+}
+
 /* Range slider */
